namespace sv_b184e9bee6964ba28ce535156fa623aa.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_b184e9bee6964ba28ce535156fa623aa.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId = 100;

    public MockChatService()
    {
        _channels = new()
        {
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering updates and technical discussions", 0),
            new(3, "design", "Design reviews and feedback", 1),
            new(4, "random", "Off-topic conversations and fun stuff", 5),
            new(5, "announcements", "Important team announcements", 0),
        };

        var now = DateTime.UtcNow;
        _messages = new()
        {
            new(1, 1, "Alice", "Hey everyone! Welcome to the new chat app.", now.AddHours(-3), null, new() { new("👋", new() { "Bob", "Carol" }), new("🎉", new() { "Dave" }) }),
            new(2, 1, "Bob", "Thanks Alice! This looks great.", now.AddHours(-2.5), null, new()),
            new(3, 1, "Carol", "Love the new design. Quick question about the sidebar — can we customize the channel order?", now.AddHours(-2), null, new() { new("👍", new() { "Alice" }) }),
            new(4, 1, "Alice", "Yes! We're planning drag-and-drop reordering for the next sprint.", now.AddHours(-1.8), 3, new()),
            new(5, 1, "Dave", "Looking forward to it. Also, are we doing standup at 10 today?", now.AddHours(-1), null, new()),
            new(6, 1, "Bob", "Has anyone reviewed the PR for the authentication module?", now.AddMinutes(-45), null, new() { new("👀", new() { "Carol" }) }),
            new(7, 1, "Carol", "I'll take a look this afternoon.", now.AddMinutes(-30), 6, new()),
            new(8, 1, "Alice", "Don't forget to update your timesheets by end of day!", now.AddMinutes(-10), null, new()),
            new(9, 2, "Dave", "The CI pipeline is green again after the fix.", now.AddHours(-1), null, new() { new("🎉", new() { "Alice", "Bob" }) }),
            new(10, 2, "Carol", "Nice work Dave! What was the root cause?", now.AddMinutes(-50), null, new()),
            new(11, 2, "Dave", "A flaky test in the integration suite. I added retry logic.", now.AddMinutes(-40), 10, new()),
            new(12, 3, "Bob", "Uploaded the new mockups for the dashboard redesign.", now.AddHours(-4), null, new() { new("🔥", new() { "Carol", "Alice" }) }),
            new(13, 3, "Carol", "These look fantastic! I have a few notes on the color palette.", now.AddHours(-3.5), 12, new()),
        };
    }

    public Task<List<Channel>> GetChannelsAsync()
        => Task.FromResult(_channels.Select(c => c with { }).ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var msgs = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderBy(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .ToList();
        return Task.FromResult(msgs);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var id = Interlocked.Increment(ref _nextMessageId);
        var msg = new Message(id, channelId, "You", content, DateTime.UtcNow, replyToId, new());
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (root == null) return Task.FromResult(new List<Message>());

        var replies = _messages
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt)
            .ToList();

        var thread = new List<Message> { root };
        thread.AddRange(replies);
        return Task.FromResult(thread);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg != null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing != null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, new() { "You" }));
            }
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        return Task.CompletedTask;
    }
}

