@* Reusable message input: textarea + submit button *@

<div class="message-input">
    <textarea @bind="Text" @bind:event="oninput" @onkeydown="HandleKeyDown"
              placeholder="@Placeholder" rows="2"></textarea>
    <button class="btn-send" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string Text { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var content = Text.Trim();
        Text = "";
        await OnSend.InvokeAsync(content);
    }
}

@* Popup emoji picker with common emojis *@

@if (Visible)
{
    <div class="emoji-picker">
        @foreach (var emoji in _emojis)
        {
            <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)" title="@emoji">
                @emoji
            </button>
        }
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = { "👍", "❤️", "😂", "🎉", "🔥", "👀" };

    private async Task SelectEmoji(string emoji)
    {
        await OnEmojiSelected.InvokeAsync(emoji);
    }
}

@* Single channel entry in the sidebar *@

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-name">
        <span class="hash">#</span> @Channel.Name
    </div>
    <div class="channel-desc">@TruncateDescription(Channel.Description)</div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</div>

@code {
    [Parameter, EditorRequired] public Services.Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnSelected { get; set; }

    private async Task HandleClick() => await OnSelected.InvokeAsync();

    private static string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..37] + "..." : desc;
}

@* Reusable message input: textarea + submit button *@

<div class="message-input">
    <textarea @bind="Text" @bind:event="oninput" @onkeydown="HandleKeyDown"
              placeholder="@Placeholder" rows="2"></textarea>
    <button class="btn-send" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
