@using sv_b184e9bee6964ba28ce535156fa623aa.Services
@* Single message with author, time, content, reactions, and hover actions *@

<div class="message-item @(IsThreadStarter ? "thread-starter" : "")"
     @onmouseenter="() => _hovered = true" @onmouseleave="HandleMouseLeave">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (IsThreadStarter && ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_hovered && ShowActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync()" title="Reply in thread">
                💬
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀
            </button>
        </div>
        <EmojiPicker Visible="_showEmojiPicker" OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public bool IsThreadStarter { get; set; }
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool ShowActions { get; set; } = true;
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private bool _hovered;
    private bool _showEmojiPicker;

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private void HandleMouseLeave()
    {
        _hovered = false;
        _showEmojiPicker = false;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

