@using sv_b184e9bee6964ba28ce535156fa623aa.Services
@inject IJSRuntime JS
@* Main message area: channel header, scrollable messages, input *@

<div class="message-area">
    <div class="message-area-header">
        <h2># @Channel.Name</h2>
        <p>@Channel.Description</p>
    </div>

    <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
        @if (_loadingMore)
        {
            <div class="loading-indicator">Loading older messages...</div>
        }
        @foreach (var msg in Messages)
        {
            var replyCount = ThreadSummaries.TryGetValue(msg.Id, out var ts) ? ts.ReplyCount : 0;
            <MessageItem Message="msg"
                         IsThreadStarter="true"
                         ReplyCount="replyCount"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                         OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{Channel.Name}")" OnSend="HandleSend" />
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private bool _loadingMore;

    private async Task HandleSend(string content)
    {
        await OnSendMessage.InvokeAsync(content);
        await ScrollToBottom();
    }

    private async Task HandleScroll()
    {
        if (_loadingMore) return;
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 10)
        {
            _loadingMore = true;
            await OnLoadMore.InvokeAsync();
            _loadingMore = false;
        }
    }

    private async Task ScrollToBottom()
    {
        await Task.Delay(50);
        await JS.InvokeVoidAsync("eval", "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
            await ScrollToBottom();
    }
}

